FROM jsonb_to_recordset('[{"id": "cap-114-math-013", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "已知甲方程式為 ( x − 4 )2 = 9，乙方程式為 ( x + 9 )2 = −4。關於甲、乙兩\n方程式的解的情形，下列敘述何者正確？", "options": ["甲有兩個相異的解，乙無解", "甲有兩個相異的解，乙有兩個相異的解", "甲有兩個相同的解，乙無解", "甲有兩個相同的解，乙有兩個相異的解"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 13, "raw_text": "13. 已知甲方程式為 ( x − 4 )2 = 9，乙方程式為 ( x + 9 )2 = −4。關於甲、乙兩\n   方程式的解的情形，下列敘述何者正確？\n   (A) 甲有兩個相異的解，乙無解\n   (B) 甲有兩個相異的解，乙有兩個相異的解\n   (C) 甲有兩個相同的解，乙無解\n   (D) 甲有兩個相同的解，乙有兩個相異的解\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-014", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "圖 ( 八 ) 為貝可咖啡店的菜單，店家今日\n準備了 120 杯咖啡和 100 個三明治販售。\n若今日準備的餐點全部售出且收入共為\n8700 元，則售出早餐組合的收入在下列\n哪一個範圍？", "options": ["4300 ～ 4399 元", "4400 ～ 4499 元", "4500 ～ 4599 元", "4600 ～ 4699 元 圖(八)"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 14, "raw_text": "14. 圖 ( 八 ) 為貝可咖啡店的菜單，店家今日\n   準備了 120 杯咖啡和 100 個三明治販售。\n   若今日準備的餐點全部售出且收入共為\n   8700 元，則售出早餐組合的收入在下列\n   哪一個範圍？\n   (A) 4300 ～ 4399 元\n   (B) 4400 ～ 4499 元\n   (C) 4500 ～ 4599 元\n   (D) 4600 ～ 4699 元\n                                          圖(八)\n\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-015", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "如圖 ( 九 )，數線上由左至右有 A(a)、B(b)、C(c)、D(d)、E(e) 五點，且\nAB = BC = CD = DE。若原點在 AE 上，且 a + b = e ，則下列關於原點\n位置的敘述，何者正確？", "options": ["在 BC 上且較接近 B 點", "在 BC 上且較接近 C 點 (C) 在 CD 上且較接近 C 點                  圖(九)", "", "在 CD 上且較接近 D 點"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 15, "raw_text": "15. 如圖 ( 九 )，數線上由左至右有 A(a)、B(b)、C(c)、D(d)、E(e) 五點，且\n  AB = BC = CD = DE。若原點在 AE 上，且 a + b = e ，則下列關於原點\n  位置的敘述，何者正確？\n  (A) 在 BC 上且較接近 B 點\n  (B) 在 BC 上且較接近 C 點\n  (C) 在 CD 上且較接近 C 點                  圖(九)\n  (D) 在 CD 上且較接近 D 點\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-016", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "如圖 ( 十 )，∆ABC 中，D 點為 AB 的中點，E 點在 AB 上，F 點在 AC 上，\n且 EF // BC。若 AF = 7，FC = 3，則下列敘述何者正確？", "options": ["DE > EB，DF 與 EC 平行", "DE > EB，DF 與 EC 不平行", "DE < EB，DF 與 EC 平行", "DE < EB，DF 與 EC 不平行 圖(十)"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 16, "raw_text": "16. 如圖 ( 十 )，∆ABC 中，D 點為 AB 的中點，E 點在 AB 上，F 點在 AC 上，\n  且 EF // BC。若 AF = 7，FC = 3，則下列敘述何者正確？\n  (A) DE > EB，DF 與 EC 平行\n  (B) DE > EB，DF 與 EC 不平行\n  (C) DE < EB，DF 與 EC 平行\n  (D) DE < EB，DF 與 EC 不平行\n\n\n\n                                           圖(十)\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-017", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "圖 ( 十一 ) 是某種螺絲釘上螺紋的示意圖，圖中的虛線皆為水平線或鉛垂線，\n圖上標示出角度，也標示出水平線間或鉛垂線間的距離。根據圖中的標示，\n判斷此種螺絲釘的螺紋深度是螺紋間距的多少倍？", "options": ["", "5", "5 3 5 3", "圖 ( 十一 )"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 17, "raw_text": "17. 圖 ( 十一 ) 是某種螺絲釘上螺紋的示意圖，圖中的虛線皆為水平線或鉛垂線，\n  圖上標示出角度，也標示出水平線間或鉛垂線間的距離。根據圖中的標示，\n  判斷此種螺絲釘的螺紋深度是螺紋間距的多少倍？\n\n  (A)\n  (B) 5\n  (C)\n      5 3\n      5 3\n  (D)\n\n\n                                圖 ( 十一 )\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-018", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "已知 a、b、c 皆為正整數，且 a、b 兩數的最大公因數與最小公倍數分別為\n11 與 88。關於 a、b、c 三數的最大公因數與最小公倍數，甲、乙兩人分別\n提出看法如下：\n甲：a、b、c 三數的最大公因數可能比 11 大\n乙：a、b、c 三數的最小公倍數可能比 88 小\n對於甲、乙兩人的看法，下列判斷何者正確？", "options": ["甲、乙皆正確", "甲、乙皆錯誤", "甲正確，乙錯誤", "甲錯誤，乙正確"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 18, "raw_text": "18. 已知 a、b、c 皆為正整數，且 a、b 兩數的最大公因數與最小公倍數分別為\n  11 與 88。關於 a、b、c 三數的最大公因數與最小公倍數，甲、乙兩人分別\n  提出看法如下：\n    甲：a、b、c 三數的最大公因數可能比 11 大\n    乙：a、b、c 三數的最小公倍數可能比 88 小\n  對於甲、乙兩人的看法，下列判斷何者正確？\n  (A) 甲、乙皆正確\n  (B) 甲、乙皆錯誤\n  (C) 甲正確，乙錯誤\n  (D) 甲錯誤，乙正確\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-019", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "圖 ( 十二 ) 為金銀河影城的價目表。某\n社團 16 人去此影城看電影，打算以比賽\n獎金 6000 元購買電影票、爆米花與\n飲料。若要讓每人拿到一張電影票和\n一杯飲料，則最多可買多少盒爆米花？", "options": ["3", "4", "5 圖 ( 十二 )", "6"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 19, "raw_text": "19. 圖 ( 十二 ) 為金銀河影城的價目表。某\n  社團 16 人去此影城看電影，打算以比賽\n  獎金 6000 元購買電影票、爆米花與\n  飲料。若要讓每人拿到一張電影票和\n  一杯飲料，則最多可買多少盒爆米花？\n  (A) 3\n  (B) 4\n  (C) 5\n                                            圖 ( 十二 )\n  (D) 6\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-020", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "圖 ( 十三 ) 為一張五邊形紙片 ABCDE，F 點在 CD 上，且以 BE、BF、FE 為\n摺線將紙片向內摺至同一平面後，A、C、D 恰重疊在同一點 P，如圖 ( 十四 ) 所\n示。若 BE > FE > BF，則根據圖 ( 十四 ) 中標示的角，判斷下列敘述何者正確？\n圖 ( 十三 )          圖 ( 十四 )", "options": ["∠3 + ∠4 = 90°，∠1 + ∠2 > ∠5 + ∠6", "∠3 + ∠4 = 90°，∠1 + ∠2 < ∠5 + ∠6", "∠3 + ∠4 ≠ 90°，∠1 + ∠2 > ∠5 + ∠6", "∠3 + ∠4 ≠ 90°，∠1 + ∠2 < ∠5 + ∠6"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 20, "raw_text": "20. 圖 ( 十三 ) 為一張五邊形紙片 ABCDE，F 點在 CD 上，且以 BE、BF、FE 為\n  摺線將紙片向內摺至同一平面後，A、C、D 恰重疊在同一點 P，如圖 ( 十四 ) 所\n  示。若 BE > FE > BF，則根據圖 ( 十四 ) 中標示的角，判斷下列敘述何者正確？\n\n\n\n\n\n\n                      圖 ( 十三 )          圖 ( 十四 )\n  (A) ∠3 + ∠4 = 90°，∠1 + ∠2 > ∠5 + ∠6\n  (B) ∠3 + ∠4 = 90°，∠1 + ∠2 < ∠5 + ∠6\n  (C) ∠3 + ∠4 ≠ 90°，∠1 + ∠2 > ∠5 + ∠6\n  (D) ∠3 + ∠4 ≠ 90°，∠1 + ∠2 < ∠5 + ∠6\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-021", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "坐標平面上有二次函數 y = −( x + 7 )2 + 12 的圖形，今將此圖形向右平移 10\n單位，平移過程中此圖形與 y 軸的交點也會跟著變化。假設此圖形與 y 軸的\n交點為 P，判斷在平移過程中，P 點位置的變化情形為下列何者？", "options": ["持續向下", "持續向上", "先向下再向上", "先向上再向下"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 21, "raw_text": "21. 坐標平面上有二次函數 y = −( x + 7 )2 + 12 的圖形，今將此圖形向右平移 10\n  單位，平移過程中此圖形與 y 軸的交點也會跟著變化。假設此圖形與 y 軸的\n  交點為 P，判斷在平移過程中，P 點位置的變化情形為下列何者？\n  (A) 持續向下\n  (B) 持續向上\n  (C) 先向下再向上\n  (D) 先向上再向下\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-022", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "如圖 ( 十五 )，∆ADG 的頂點 G 為 ∆ABC 的重心，DG 與 AB 相交於 E 點。\n若 DE：EG = 3：2，AE：EB = 3：4，則 ∆ADG 面積為 ∆ABC 面積的多少倍？", "options": ["", "5", "5", "5 圖 ( 十五 )"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 22, "raw_text": "22. 如圖 ( 十五 )，∆ADG 的頂點 G 為 ∆ABC 的重心，DG 與 AB 相交於 E 點。\n  若 DE：EG = 3：2，AE：EB = 3：4，則 ∆ADG 面積為 ∆ABC 面積的多少倍？\n\n  (A)\n  (B) 5\n  (C) 5\n  (D) 5\n                                             圖 ( 十五 )\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-023", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "如圖 ( 十六 )，∆ABC 的三個頂點都在一圓上，固定 A 點將 ∆ABC 依順時針\n方向旋轉，旋轉後的三角形為 ∆AB′C′，且 B′ 會落在同一圓上，其中 AB 與\nAC′ 的夾角為 x°。若 BC = 54°，CA = 62°，則 x 值為何？", "options": ["27", "31", "32", "37 圖 ( 十六 )"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 23, "raw_text": "23. 如圖 ( 十六 )，∆ABC 的三個頂點都在一圓上，固定 A 點將 ∆ABC 依順時針\n    方向旋轉，旋轉後的三角形為 ∆AB′C′，且 B′ 會落在同一圓上，其中 AB 與\n  AC′ 的夾角為 x°。若 BC = 54°，CA = 62°，則 x 值為何？\n  (A) 27\n  (B) 31\n  (C) 32\n  (D) 37\n\n\n\n\n                                             圖 ( 十六 )\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-024", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "小桃騎乘該自行車時， 原本使用的前齒輪為 33 齒， 後齒輪為 21 齒。根據上\n文，他從原本的前後齒輪組合切換成下列四種組合中的哪一種後，踩起來最\n費力？", "options": ["前齒輪不變，後齒輪切換為 18 齒", "前齒輪不變，後齒輪切換為 24 齒", "前齒輪切換為 22 齒，後齒輪不變", "前齒輪切換為 44 齒，後齒輪不變"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-114-math-passage-24", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 24, "raw_text": "24. 小桃騎乘該自行車時， 原本使用的前齒輪為 33 齒， 後齒輪為 21 齒。根據上\n  文，他從原本的前後齒輪組合切換成下列四種組合中的哪一種後，踩起來最\n  費力？\n  (A) 前齒輪不變，後齒輪切換為 18 齒\n  (B) 前齒輪不變，後齒輪切換為 24 齒\n  (C) 前齒輪切換為 22 齒，後齒輪不變\n  (D) 前齒輪切換為 44 齒，後齒輪不變\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-114-math-025", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-114-math", "question_type": "single_choice", "question_text": "即使是不同的前齒輪齒數與後齒輪齒數的組合，仍可能產生相同的齒輪比，\n因此小桃這輛 18 段變速自行車實際上只能夠產生 14 種不同的齒輪比。根據\n上文，判斷這輛自行車切換前齒輪齒數與後齒輪齒數的組合時，下列哪一個\n齒輪比有最多種組合？", "options": ["", "11", "11", "11"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-114-math-passage-24", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:42+00:00", "source_pdf_sha1": "534f44e0befe", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["option_incomplete"], "parse_confidence": 0.75, "original_question_number": 25, "raw_text": "25. 即使是不同的前齒輪齒數與後齒輪齒數的組合，仍可能產生相同的齒輪比，\n  因此小桃這輛 18 段變速自行車實際上只能夠產生 14 種不同的齒輪比。根據\n  上文，判斷這輛自行車切換前齒輪齒數與後齒輪齒數的組合時，下列哪一個\n  齒輪比有最多種組合？\n\n  (A)\n  (B) 11\n  (C) 11\n  (D) 11\n\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
